// Keep only fields required by the LLM

return items.map(item => {

    const r = item.json;

    return {
        json: {
            review_id: r.original_review_id,
            source: r.source,
            country: r.country,
            rating: r.rating,
            discovery_score: r.discovery_score,
            categories: r.categories,
            review: r.review
        }
    };

});

// Get metadata from the Build Prompt node
const batch = $('buildPromptNode').first().json;

let text = "";

try {

    // Gemini response
    if (
        $json.content &&
        $json.content.parts &&
        $json.content.parts.length > 0
    ) {
        text = $json.content.parts[0].text;
    }

    else if ($json.text) {
        text = $json.text;
    }

    else if ($json.output) {
        text = $json.output;
    }

    else {
        throw new Error("No Gemini text found.");
    }

    // Remove markdown fences if Gemini adds them
    text = text
        .replace(/^```json/i, "")
        .replace(/^```/, "")
        .replace(/```$/, "")
        .trim();

    const analysis = JSON.parse(text);

    return [{
        json: {
            batch_id: batch.batch_id,
            batch_number: batch.batch_number,
            review_count: batch.review_count,
            review_range: batch.review_range,
            generated_at: new Date().toISOString(),
            analysis
        }
    }];

}
catch(err){

    return [{
        json:{
            batch_id: batch.batch_id,
            parse_error:true,
            error:err.message,
            raw:text
        }
    }];

}

// If Gemini already returned a parsed object, use it directly.
if ($json.themes || $json.top_requests) {
  return [{ json: $json }];
}

let text = "";

if ($json.text) {
    text = $json.text;
} else if ($json.output) {
    text = $json.output;
} else if ($json.response) {
    text = $json.response;
} else {
    text = JSON.stringify($json);
}

text = text
    .replace(/^```json/i, "")
    .replace(/^```/, "")
    .replace(/```$/, "")
    .trim();

try {
    return [{
        json: JSON.parse(text)
    }];
} catch (e) {
    return [{
        json: {
            parse_error: true,
            error: e.message,
            raw: text
        }
    }];
}
